class Solution:
    def maxScore(self, nums: List[int], x: int) -> int:
        even = nums[0] if nums[0] % 2 == 0 else -x
        odd = nums[0] if nums[0] % 2 != 0 else -x

        for num in nums[1:]:
            if num % 2 == 0:
                even = max(even + num, odd + num - x)
            else:
                odd = max(odd + num, even + num - x)

        return max(even, odd)
